import Foundation
import UIKit

// MARK: - Analytics and Debugging Module

class AnalyticsDebugger {

    static let shared = AnalyticsDebugger()

    private init() {
        // Optional: Initialize any internal logging mechanisms or observers here
    }

    // MARK: - Configuration

    var isLoggingEnabled: Bool = true
    var shouldLogSensitiveData: Bool = false // Toggle to control sensitive data logging

    // MARK: - Core Logging Function

    private func log(_ message: String, level: LogLevel, file: String = #file, function: String = #function, line: Int = #line) {
        guard isLoggingEnabled else { return }

        let fileName = (file as NSString).lastPathComponent
        let timestamp = DateFormatter.localizedString(from: Date(), dateStyle: .short, timeStyle: .medium)

        let logEntry = "[\(timestamp)] [\(level.rawValue)] [\(fileName):\(line)] \(function): \(message)"

        NSLog("%@", logEntry) // Use NSLog for system-level logging
        print(logEntry)       // Use print for console output
    }

    // MARK: - Log Levels

    enum LogLevel: String {
        case debug = "DEBUG"
        case info = "INFO"
        case warning = "WARNING"
        case error = "ERROR"
        case sensitive = "SENSITIVE" // For data that might be toggled off
    }

    // MARK: - Public Logging Methods

    func debug(_ message: String, file: String = #file, function: String = #function, line: Int = #line) {
        log(message, level: .debug, file: file, function: function, line: line)
    }

    func info(_ message: String, file: String = #file, function: String = #function, line: Int = #line) {
        log(message, level: .info, file: file, function: function, line: line)
    }

    func warning(_ message: String, file: String = #file, function: String = #function, line: Int = #line) {
        log(message, level: .warning, file: file, function: function, line: line)
    }

    func error(_ message: String, error: Error? = nil, file: String = #file, function: String = #function, line: Int = #line) {
        var fullMessage = message
        if let error = error {
            fullMessage += " Error: \(error.localizedDescription)"
            if let nsError = error as NSError? {
                fullMessage += " (Domain: \(nsError.domain), Code: \(nsError.code), UserInfo: \(nsError.userInfo))"
            }
        }
        log(fullMessage, level: .error, file: file, function: function, line: line)
    }

    // MARK: - Specific Tracking Methods

    func trackUserInteraction(screen: String, element: String, action: String, userId: String? = nil) {
        var message = "User Interaction: Screen='\(screen)', Element='\(element)', Action='\(action)'"
        if let userId = userId {
            message += ", UserID='\(userId)'"
        }
        info(message)
    }

    func trackAuthentication(flow: String, status: String, userId: String? = nil, email: String? = nil, token: String? = nil) {
        var message = "Auth Flow: Flow='\(flow)', Status='\(status)'"
        if let userId = userId {
            message += ", UserID='\(userId)'"
        }
        if shouldLogSensitiveData {
            if let email = email {
                message += ", Email='\(email)'"
            }
            if let token = token {
                message += ", Token='\(token)'"
            }
            log(message, level: .sensitive)
        } else {
            info(message)
        }
    }

    func trackAPIRequest(endpoint: String, method: String, userId: String? = nil, payload: [String: Any]? = nil, headers: [String: String]? = nil) {
        var message = "API Request: Endpoint='\(endpoint)', Method='\(method)'"
        if let userId = userId {
            message += ", UserID='\(userId)'"
        }
        if shouldLogSensitiveData {
            if let payload = payload, let data = try? JSONSerialization.data(withJSONObject: payload, options: .prettyPrinted), let payloadString = String(data: data, encoding: .utf8) {
                message += ", Payload: \(payloadString)"
            }
            if let headers = headers {
                message += ", Headers: \(headers)"
            }
            log(message, level: .sensitive)
        } else {
            info(message)
        }
    }

    func trackAPIResponse(endpoint: String, method: String, statusCode: Int, userId: String? = nil, responseData: Data? = nil, error: Error? = nil) {
        var message = "API Response: Endpoint='\(endpoint)', Method='\(method)', Status Code=\(statusCode)"
        if let userId = userId {
            message += ", UserID='\(userId)'"
        }

        if let error = error {
            message += ", Error: \(error.localizedDescription)"
            self.error(message, error: error)
            return
        }

        if shouldLogSensitiveData {
            if let responseData = responseData, let json = try? JSONSerialization.jsonObject(with: responseData, options: []),
               let prettyPrintedData = try? JSONSerialization.data(withJSONObject: json, options: .prettyPrinted),
               let responseString = String(data: prettyPrintedData, encoding: .utf8) {
                message += ", Response Data: \(responseString)"
            } else if let responseData = responseData, let responseString = String(data: responseData, encoding: .utf8) {
                message += ", Response Data: \(responseString)"
            }
            log(message, level: .sensitive)
        } else {
            info(message)
        }
    }

    func trackUserDataChange(userId: String, field: String, oldValue: Any?, newValue: Any?) {
        var message = "User Data Change: UserID='\(userId)', Field='\(field)'"
        if shouldLogSensitiveData {
            message += ", Old Value='\(String(describing: oldValue))', New Value='\(String(describing: newValue))'"
            log(message, level: .sensitive)
        } else {
            info(message)
        }
    }

    func trackErrorCondition(domain: String, code: Int, description: String, userInfo: [String: Any]? = nil, userId: String? = nil) {
        var message = "Error Condition: Domain='\(domain)', Code='\(code)', Description='\(description)'"
        if let userId = userId {
            message += ", UserID='\(userId)'"
        }
        if let userInfo = userInfo {
            message += ", UserInfo='\(userInfo)'"
        }
        error(message)
    }

    // MARK: - Utility for JSON Payload Conversion

    private func jsonString(from dictionary: [String: Any]?) -> String? {
        guard let dictionary = dictionary else { return nil }
        do {
            let data = try JSONSerialization.data(withJSONObject: dictionary, options: .prettyPrinted)
            return String(data: data, encoding: .utf8)
        } catch {
            self.error("Failed to convert dictionary to JSON string: \(error.localizedDescription)")
            return nil
        }
    }
}

